import React from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';

export default function Navbar() {
  const navigate = useNavigate();
  const location = useLocation();
  const token = localStorage.getItem('token');
  const logout = () => {
    localStorage.removeItem('token');
    navigate('/login');
  };

  const linkBase =
    'text-sm px-3 py-1.5 rounded-md transition-colors duration-200';

  return (
    <nav className="sticky top-0 z-40 backdrop-blur supports-[backdrop-filter]:bg-white/70 bg-white/60 border-b">
      <div className="max-w-6xl mx-auto px-4 py-3 flex items-center justify-between">
        <Link to="/" className="font-semibold text-lg tracking-tight">
          <span className="bg-gradient-to-r from-blue-600 via-indigo-600 to-fuchsia-600 bg-clip-text text-transparent">Task Manager</span>
        </Link>
        <div className="flex items-center gap-2">
          {token && (
            <Link
              to="/tasks/new"
              className={`${linkBase} bg-gradient-to-r from-blue-600 to-indigo-600 text-white shadow hover:from-blue-700 hover:to-indigo-700`}
            >
              Add Task
            </Link>
          )}
          {token ? (
            <button
              onClick={logout}
              className={`${linkBase} border hover:bg-gray-100`}
            >
              Logout
            </button>
          ) : (
            <>
              <Link
                to="/login"
                className={`${linkBase} border ${location.pathname === '/login' ? 'bg-gray-100' : 'hover:bg-gray-100'}`}
              >
                Login
              </Link>
              <Link
                to="/register"
                className={`${linkBase} bg-gray-900 text-white hover:bg-black`}
              >
                Register
              </Link>
            </>
          )}
        </div>
      </div>
    </nav>
  );
}
